// Auth state contract
// Files: src/contexts/AuthContext.tsx, src/hooks/useAuth.ts, src/hooks/useSession.ts

// Import from '@/contexts'
export interface AuthContextValue {
  user: import('@/types').User | null;           // validated public.users profile
  session: import('@/lib').Session | null;       // Supabase auth session
  loading: boolean;
  isAuthenticated: boolean;
  signInWithGoogle: () => Promise<void>;
  signOut: () => Promise<void>;
}
export declare const AuthContext: React.Context<AuthContextValue | undefined>;
export declare function AuthProvider(props: { children: React.ReactNode }): React.ReactElement;

// Import from '@/hooks'
export declare function useAuth(): AuthContextValue;

export interface UseSessionResult {
  session: import('@/lib').Session | null;
  authUser: import('@/lib').User | null;
  expiresAt: number | null;
  expiresAtDate: Date | null;
  hasExpired: () => boolean;
  isExpiringSoon: (thresholdSeconds?: number) => boolean;
  refreshSession: () => Promise<import('@/lib').Session | null>;
}
export declare function useSession(): UseSessionResult;

// Behavior notes
// - AuthProvider restores the current session on mount via supabase.auth.getSession()
// - AuthProvider listens to supabase.auth.onAuthStateChange() and refetches the public.users row
// - public.users data is validated with UserSchema before being stored in context
// - web redirect target: `${window.location.origin}/auth/callback`
// - native redirect target: `worktracker://auth/callback`
